                exec: (callback: any) => callback(new Error('Delete error'), null)
            } as any);

            await removeIndustry(req as Request, res as Response);

            expect(jsonStub.calledWith({ status: Status.Error, message: Messages.GenericError })).to.be.true;
        });
    });
});

