import { Request, Response } from 'express';
import { Status, Messages } from '../common/constants';

import { JobSite, IJobSite } from '../models/JobSite';
import { JobLocation } from '../models/JobLocation';
import * as Sentry from '@sentry/node';
import escapeStringRegexp from 'escape-string-regexp';
import { Types } from 'mongoose';

interface JobSiteAddress {
    city?: string;
    state?: string;
    street?: string;
    zipcode?: string;
}

interface JobSiteLocation {
    coordinates?: any[];
    lat?: any;
    long?: any;
    lng?: any;
    latitude?: any;
    longitude?: any;
}

const hasValue = (value: any): boolean => value !== undefined && value !== null && value !== '';

const normalizeName = (name: any): any => typeof name === 'string' ? name.trim() : name;

const normalizeAddress = (address: any): JobSiteAddress | undefined => {
    if (!address || typeof address !== 'object') {
        return undefined;
    }

    const normalizedAddress: JobSiteAddress = {
        street: address.street,
        city: address.city,
        state: address.state,
        zipcode: address.zipcode ?? address.zipCode,
    };

    return Object.values(normalizedAddress).some(hasValue) ? normalizedAddress : undefined;
};

const mergeAddress = (currentAddress: any, incomingAddress: any): JobSiteAddress | undefined => {
    if (!incomingAddress || typeof incomingAddress !== 'object') {
        return currentAddress;
    }

    const mergedAddress: JobSiteAddress = {
        street: currentAddress?.street,
        city: currentAddress?.city,
        state: currentAddress?.state,
        zipcode: currentAddress?.zipcode,
    };
    const addressFields: Array<keyof JobSiteAddress> = ['street', 'city', 'state', 'zipcode'];

    addressFields.forEach((field: keyof JobSiteAddress) => {
        const incomingValue = field === 'zipcode' ? incomingAddress.zipcode ?? incomingAddress.zipCode : incomingAddress[field];
        if (incomingValue !== undefined && incomingValue !== null) {
            mergedAddress[field] = incomingValue;
        }
    });

    return Object.values(mergedAddress).some((value: any) => value !== undefined && value !== null) ? mergedAddress : undefined;
};

const normalizeCoordinates = (params: any): any[] | undefined => {
    const location: JobSiteLocation = params.location || {};

    if (Array.isArray(location.coordinates) && location.coordinates.length >= 2 && hasValue(location.coordinates[0]) && hasValue(location.coordinates[1])) {
        return [location.coordinates[0], location.coordinates[1]];
    }

    const lat = location.lat ?? location.latitude ?? params.locationLat ?? params.lat ?? params.latitude;
    const long = location.long ?? location.lng ?? location.longitude ?? params.locationLong ?? params.long ?? params.lng ?? params.longitude;

    return hasValue(lat) && hasValue(long) ? [long, lat] : undefined;
};

const normalizeObjectId = (value: any): any => {
    if (!value) {
        return value;
    }

    const stringValue = value.toString();
    return Types.ObjectId.isValid(stringValue) ? new Types.ObjectId(stringValue) : value;
};

const firstOwnerId = (value: any): any => Array.isArray(value) ? value[0] : value;

const getLocationOwnership = (jobLocation: any): { customerId?: any; homeOwner?: any } => {
    const customerId = jobLocation?.customerId ?? firstOwnerId(jobLocation?.customerIds);
    const homeOwner = jobLocation?.homeOwner ?? jobLocation?.homeOwnerId;
    const ownership: { customerId?: any; homeOwner?: any } = {};

    if (customerId) {
        ownership.customerId = normalizeObjectId(customerId);
    }
    if (homeOwner) {
        ownership.homeOwner = normalizeObjectId(homeOwner);
    }

    return ownership;
};

const getIdValue = (value: any): any => value?._id ?? value;

const duplicateNameQuery = (name: any, locationId: any, excludedId?: any): any => {
    const query: any = {
        name,
        locationId: normalizeObjectId(locationId),
    };

    if (excludedId) {
        query._id = { $ne: normalizeObjectId(excludedId) };
    }

    return query;
};

const isDuplicateJobSiteName = async (name: any, locationId: any, excludedId?: any): Promise<boolean> => {
    const duplicateJobSite = await JobSite.findOne(duplicateNameQuery(name, locationId, excludedId)).lean();
    return !!duplicateJobSite;
};


export const get = async (req: Request, res: Response) => {
    const { id } = req.params;
    const { query: queryParams = {} } = req;
    const { customerId, homeOwnerId, locationId, isActive } = queryParams;

    console.log('Query Params:', queryParams);

    let query: {
        _id?: string;
        customerId?: string;
        locationId?: Types.ObjectId;
        homeOwner?: string;
        $or?: Array<{[key: string]: any}>;
        isActive?: boolean;
    } = {};

    if (id) {
        query = { _id: id };
    } else if (customerId && locationId) {
        query = { customerId, locationId: new Types.ObjectId(locationId) };
    } else if (homeOwnerId && locationId) {
        query = { homeOwner: homeOwnerId, locationId: new Types.ObjectId(locationId) };
    } else if (customerId && !homeOwnerId) {
        query = { customerId };
    } else if (customerId && homeOwnerId) {
        query = { $or: [{ customerId }, { homeOwner: homeOwnerId }] };
    } else if (homeOwnerId && !customerId) {
        query = { homeOwner: homeOwnerId };
    } else if (locationId) {
        query = { locationId: new Types.ObjectId(locationId) };
    } 

    switch (isActive) {
    case 'true':
    case true:
        query = {...query, $or: [...(query.$or || []), { isActive: true }, { isActive: { $exists: false } }] };
        break;
    case 'false':
    case false:
        query = {...query, isActive: false};
        break;
    default:
        // Retrieve all job sites
        break;
    }

    try {
        const jobSites = await JobSite.find(query).lean();
        res.status(Status.OK).json(jobSites);
    } catch (err) {
        console.error('Error in get JobSite:', err);
        res.status(Status.InternalError).json({ status: Status.Error, message: Messages.InternalServerError });
    }
};

export const create = async (req: Request, res: Response) => {
    const params = req.body || {};
    const name = normalizeName(params.name);
    const locationId = params.locationId;
    const address = normalizeAddress(params.address);
    const coordinates = normalizeCoordinates(params);

    // Validate required parameters
    const missingParams = [];
    if (!name) missingParams.push('name');
    if (!locationId) missingParams.push('locationId');

    if (missingParams.length > 0) {
        const message = `${Messages.MissingParams}: ${missingParams.join(', ')}`;
        return res.status(400).json({ status: Status.Error, message });
    }

    if (!coordinates && !address) {
        return res.status(400).json({ status: Status.Error, message: 'Either location or address is required.' });
    }

    try {
        // Find the job location
        const jobLocation = await JobLocation.findById(locationId, { customerId: 1, customerIds: 1, homeOwner: 1, homeOwnerId: 1 });

        if (!jobLocation) {
            return res.status(404).json({ status: Status.Error, message: 'Subdivision not found.' });
        }

        if (await isDuplicateJobSiteName(name, locationId)) {
            return res.status(400).json({ status: Status.Error, message: 'Job Address already exists in this subdivision.' });
        }

        const ownership = getLocationOwnership(jobLocation);
        const jobSiteData: any = {
            name,
            address,
            locationId: normalizeObjectId(locationId),
            ...ownership,
        };

        if (coordinates) {
            jobSiteData.location = {
                coordinates
            };
        }

        // Create the new job site
        const newJobSite: IJobSite = await JobSite.create(jobSiteData);

        // Update the job location with the new job site
        await JobLocation.findByIdAndUpdate(locationId, {
            $push: { jobSites: newJobSite._id }
        });

        return res.status(Status.OK).json(newJobSite);

    } catch (error) {
        Sentry.captureException(error);
        console.error('Error in create job site:', error);
        return res.status(500).json({ status: Status.Error, message: Messages.InternalServerError });
    }
};

export const update = async (req: Request, res: Response) => {
    const params = req.body || {};
    const { id } = req.params;
    const name = normalizeName(params.name);

    const missingParams = [];
    if (!id) missingParams.push('id');
    const isMissingParams = missingParams.length > 0;

    if (isMissingParams) {
        const message = `${Messages.MissingParams}: ${missingParams.join(', ')}`;
        return res.json({ status: Status.Error, message });
    }

    try {
        const jobSite = await JobSite.findById(id).exec();
        if (!jobSite) {
            return res.json({ status: Status.Error, message: 'Job Address not found.' });
        }

        const currentLocationId = getIdValue(jobSite.locationId);
        const locationId = params.locationId ?? currentLocationId;
        let ownership = {
            customerId: jobSite.customerId,
            homeOwner: jobSite.homeOwner,
        };

        if (params.locationId) {
            const jobLocation = await JobLocation.findById(locationId, { customerId: 1, customerIds: 1, homeOwner: 1, homeOwnerId: 1 });
            if (!jobLocation) {
                return res.json({ status: Status.Error, message: 'Subdivision not found.' });
            }
            ownership = { ...ownership, ...getLocationOwnership(jobLocation) };
        }

        const currentName = jobSite.name;
        const nextName = name ?? currentName;
