            status: statusStub,
            json: jsonStub,
        };
        statusStub.returns(res);
    });

    afterEach(() => {
        sinon.restore();
    });

    const stubNoDuplicateName = () => {
        return sinon.stub(JobSite as any, 'findOne').returns({
            lean: sinon.stub().resolves(null),
        });
    };

    describe('create', () => {
        it('creates an address-only job site using ownership from the subdivision', async () => {
            const locationId = new Types.ObjectId();
            const customerId = new Types.ObjectId();
            const homeOwner = new Types.ObjectId();
            const siteId = new Types.ObjectId();
            const newJobSite = { _id: siteId, name: 'Lot 12' };
            req.body = {
                name: 'Lot 12',
                locationId: locationId.toString(),
                address: {
                    street: '123 Main St',
                    city: 'Austin',
                    state: 'TX',
                    zipcode: '78701',
                },
            };

            sinon.stub(JobLocation as any, 'findById').resolves({
                _id: locationId,
                customerIds: [customerId],
                homeOwner,
            });
            stubNoDuplicateName();
            const createStub = sinon.stub(JobSite as any, 'create').resolves(newJobSite);
            const updateLocationStub = sinon.stub(JobLocation as any, 'findByIdAndUpdate').resolves({});

            await jobSiteController.create(req as Request, res as Response);

            expect(createStub.calledOnce).to.be.true;
            const createArgs = createStub.firstCall.args[0];
            expect(createArgs.name).to.equal('Lot 12');
            expect(createArgs.address).to.deep.equal(req.body.address);
            expect(createArgs.location).to.equal(undefined);
            expect(createArgs.locationId.toString()).to.equal(locationId.toString());
            expect(createArgs.customerId.toString()).to.equal(customerId.toString());
            expect(createArgs.homeOwner.toString()).to.equal(homeOwner.toString());
            expect(updateLocationStub.calledOnce).to.be.true;
            expect(updateLocationStub.firstCall.args[0]).to.equal(locationId.toString());
            expect(updateLocationStub.firstCall.args[1]).to.deep.equal({ $push: { jobSites: siteId } });
            expect(statusStub.calledWith(Status.OK)).to.be.true;
            expect(jsonStub.calledWith(newJobSite)).to.be.true;
        });

        it('rejects create requests without coordinates or address data', async () => {
            req.body = {
                name: 'Lot 12',
                locationId: new Types.ObjectId().toString(),
            };
            const findLocationStub = sinon.stub(JobLocation as any, 'findById');

            await jobSiteController.create(req as Request, res as Response);

            expect(findLocationStub.notCalled).to.be.true;
            expect(statusStub.calledWith(400)).to.be.true;
            expect(jsonStub.calledWith({
                status: Status.Error,
                message: 'Either location or address is required.',
            })).to.be.true;
        });

        it('rejects duplicate job address names within the same subdivision', async () => {
            const locationId = new Types.ObjectId();
            req.body = {
                name: 'Lot 12',
                locationId: locationId.toString(),
                location: {
                    lat: 30.2672,
                    long: -97.7431,
                },
            };

            sinon.stub(JobLocation as any, 'findById').resolves({
                _id: locationId,
                customerIds: [new Types.ObjectId()],
            });
            const findOneStub = sinon.stub(JobSite as any, 'findOne').returns({
                lean: sinon.stub().resolves({ _id: new Types.ObjectId(), name: 'Lot 12' }),
            });
            const createStub = sinon.stub(JobSite as any, 'create');

            await jobSiteController.create(req as Request, res as Response);

            expect(findOneStub.calledOnce).to.be.true;
            const duplicateQuery = findOneStub.firstCall.args[0];
            expect(duplicateQuery.name).to.equal('Lot 12');
            expect(duplicateQuery.locationId.toString()).to.equal(locationId.toString());
            expect(createStub.notCalled).to.be.true;
            expect(statusStub.calledWith(400)).to.be.true;
            expect(jsonStub.calledWith({
                status: Status.Error,
                message: 'Job Address already exists in this subdivision.',
            })).to.be.true;
        });
    });

    describe('update', () => {
        it('preserves address, coordinates, owner fields, and active flag when optional fields are omitted', async () => {
            const id = new Types.ObjectId();
            const locationId = new Types.ObjectId();
            const customerId = new Types.ObjectId();
            const homeOwner = new Types.ObjectId();
            const existingJobSite = {
                _id: id,
                name: 'Lot 12',
                address: {
                    street: '123 Main St',
                    city: 'Austin',
                    state: 'TX',
                    zipcode: '78701',
                },
                location: {
                    coordinates: [-97.7431, 30.2672],
                },
                locationId,
                customerId,
                homeOwner,
                isActive: false,
            };
            req.params = { id: id.toString() };
            req.body = {};

            sinon.stub(JobSite as any, 'findById').returns({
                exec: sinon.stub().resolves(existingJobSite),
            });
            const updateStub = sinon.stub(JobSite as any, 'updateOne').returns({
                exec: sinon.stub().resolves({ n: 1, nModified: 0 }),
            });

            await jobSiteController.update(req as Request, res as Response);

            expect(updateStub.calledOnce).to.be.true;
            expect(updateStub.firstCall.args[0]).to.deep.equal({ _id: id.toString() });
            const updateData = updateStub.firstCall.args[1].$set;
            expect(updateData.name).to.equal(existingJobSite.name);
            expect(updateData.address).to.deep.equal(existingJobSite.address);
            expect(updateData.location).to.deep.equal(existingJobSite.location);
            expect(updateData.locationId.toString()).to.equal(locationId.toString());
            expect(updateData.customerId.toString()).to.equal(customerId.toString());
            expect(updateData.homeOwner.toString()).to.equal(homeOwner.toString());
            expect(updateData.isActive).to.equal(false);
            expect(jsonStub.calledWith({
                status: Status.OK,
                message: 'Job Address has been updated successfully.',
            })).to.be.true;
        });

        it('rejects an updated name that already exists in the same subdivision', async () => {
            const id = new Types.ObjectId();
            const locationId = new Types.ObjectId();
            const existingJobSite = {
                _id: id,
                name: 'Lot 12',
                locationId,
                customerId: new Types.ObjectId(),
                isActive: true,
            };
            req.params = { id: id.toString() };
            req.body = { name: 'Lot 13' };

            sinon.stub(JobSite as any, 'findById').returns({
                exec: sinon.stub().resolves(existingJobSite),
            });
            const findOneStub = sinon.stub(JobSite as any, 'findOne').returns({
                lean: sinon.stub().resolves({ _id: new Types.ObjectId(), name: 'Lot 13' }),
            });
            const updateStub = sinon.stub(JobSite as any, 'updateOne');

            await jobSiteController.update(req as Request, res as Response);

            expect(findOneStub.calledOnce).to.be.true;
            const duplicateQuery = findOneStub.firstCall.args[0];
            expect(duplicateQuery.name).to.equal('Lot 13');
            expect(duplicateQuery.locationId.toString()).to.equal(locationId.toString());
            expect(duplicateQuery._id.$ne.toString()).to.equal(id.toString());
            expect(updateStub.notCalled).to.be.true;
            expect(statusStub.calledWith(400)).to.be.true;
            expect(jsonStub.calledWith({
                status: Status.Error,
                message: 'Job Address already exists in this subdivision.',
            })).to.be.true;
        });
    });
});
